import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { ArrowLeft, Calendar, AlertCircle } from "lucide-react";
import CaseTabs from "./CaseTabs.js";
import TimelineTab from "./TimelineTab.js";
import MembersTab from "./MembersTab.js";
import EvidenceTab from "./EvidenceTab.js";
import "../../components/Components.css";
import api from "../../api.js";

const PRIORITY_MAP = {
  3: { label: "High", color: "#f87171", bg: "rgba(239,68,68,0.1)" },
  2: { label: "Medium", color: "#fbbf24", bg: "rgba(245,158,11,0.1)" },
  1: { label: "Low", color: "#34d399", bg: "rgba(16,185,129,0.1)" },
};

const STATUS_MAP = {
  Open: { color: "#34d399", bg: "rgba(52,211,153,0.1)" },
  Close: { color: "#f87171", bg: "rgba(239,68,68,0.1)" },
  Archived: { color: "#94a3b8", bg: "rgba(148,163,184,0.1)" },
};

export default function CaseDetails() {
  const { caseId } = useParams();
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));
  const isAdmin = user?.role_id === 1;

  const [caseData, setCaseData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [statusUpdating, setStatusUpdating] = useState(false);

  // ✅ FIXED FETCH
  const fetchCase = async () => {
    try {
      setLoading(true);

      const res = await api.get(`/case/${caseId}`);

      // 🔥 SAFE DATA FIX (IMPORTANT)
      const data = res.data;

      setCaseData({
        ...data,
        members: Array.isArray(data.members) ? data.members : [],
        leadInvestigators: Array.isArray(data.leadInvestigators)
          ? data.leadInvestigators
          : [],
        memberDetails: Array.isArray(data.memberDetails)
          ? data.memberDetails
          : [],
      });
    } catch (err) {
      if (err.response?.status === 403) {
        setError("You do not have access to this case.");
      } else {
        setError("Case not found.");
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCase();
  }, [caseId]);

  const handleStatusChange = async (newStatus) => {
    if (!isAdmin) return;

    setStatusUpdating(true);

    try {
      await api.patch(`/case/${caseId}/status`, {
        status: newStatus,
      });

      setCaseData((prev) => ({
        ...prev,
        status: newStatus,
      }));
    } catch {
      alert("Failed to update status");
    } finally {
      setStatusUpdating(false);
    }
  };

  const handleDeleteCase = async () => {
    if (
      !window.confirm(
        `Delete case "${caseData?.title}"? This cannot be undone.`
      )
    )
      return;

    try {
      await api.delete(`/case/${caseId}`);
      navigate("/cases");
    } catch {
      alert("Failed to delete case");
    }
  };

  const priority =
    PRIORITY_MAP[caseData?.priority] || PRIORITY_MAP[1];

  const statusStyle =
    STATUS_MAP[caseData?.status] || STATUS_MAP["Open"];

  const formatDate = (d) =>
    d
      ? new Date(d).toLocaleDateString("en-GB", {
          day: "2-digit",
          month: "short",
          year: "numeric",
        })
      : "—";

  // ✅ FIXED TABS (SAFE DATA)
  const tabs = caseData
    ? [
        {
          label: "Timeline",
          content: (
            <TimelineTab caseId={caseId} caseData={caseData} />
          ),
        },
        {
          label: "Members",
          content: (
            <MembersTab
              members={caseData.members}
              leadInvestigators={caseData.leadInvestigators}
              memberDetails={caseData.memberDetails}
              caseId={caseId}
              isAdmin={isAdmin}
              onRefresh={fetchCase}
            />
          ),
        },
        {
          label: "Evidence",
          content: (
            <EvidenceTab
              caseId={caseId}
              userRole={user?.role_id}
            />
          ),
        },
      ]
    : [];

  // LOADING
  if (loading)
    return (
      <div className="detailsPage">
        <p>Loading case details...</p>
      </div>
    );

  // ERROR
  if (error)
    return (
      <div className="detailsPage">
        <button onClick={() => navigate(-1)}>
          <ArrowLeft size={18} /> Back
        </button>

        <div>
          <AlertCircle size={48} color="#f87171" />
          <p>{error}</p>
        </div>
      </div>
    );

  return (
    <div className="detailsPage">
      <button onClick={() => navigate(-1)}>
        <ArrowLeft size={18} /> Back to Cases
      </button>

      <div className="detailsGlassCard">
        {/* HEADER */}
        <header>
          <div>
            <span>Case #{caseId}</span>
            <span style={statusStyle}>{caseData?.status}</span>
            <span style={priority}>{priority.label} Priority</span>

            <h1>{caseData?.title}</h1>
            <p>{caseData?.description}</p>
          </div>

          {isAdmin && (
            <div>
              <select
                value={caseData?.status}
                onChange={(e) =>
                  handleStatusChange(e.target.value)
                }
                disabled={statusUpdating}
              >
                <option value="Open">Open</option>
                <option value="Close">Close</option>
                <option value="Archived">Archived</option>
              </select>

              <button onClick={handleDeleteCase}>
                Delete Case
              </button>
            </div>
          )}
        </header>

        {/* INFO */}
        <div>
          <div>
            <h4>Lead Investigators</h4>
            <p>
              {caseData.leadInvestigators.length
                ? caseData.leadInvestigators.join(", ")
                : "Unassigned"}
            </p>
          </div>

          <div>
            <h4>Total Members</h4>
            <p>{caseData.members.length}</p>
          </div>

          <div>
            <h4>Start Date</h4>
            <p>{formatDate(caseData.start_date)}</p>
          </div>

          <div>
            <h4>End Date</h4>
            <p>
              {caseData.end_date
                ? formatDate(caseData.end_date)
                : "Ongoing"}
            </p>
          </div>
        </div>

        {/* TABS */}
        <CaseTabs tabs={tabs} />
      </div>
    </div>
  );
}
